beforeSaveCustomScript:
$workDurationSeconds = entity\attribute('workDurationSeconds');
$avgWorkDurationSeconds = entity\attribute('avgWorkDurationSeconds');
$overtimeSeconds = entity\attribute('overtimeSeconds');
$avgOvertime = entity\attribute('avgOvertimeSeconds');

// 🔹 Convert seconds → HH:mm:ss
ifThenElse($workDurationSeconds, 
    // 🔹 Convert seconds → HH:mm:ss
    $diff = $workDurationSeconds;
    $hours   = ($diff - ($diff % 3600)) / 3600;
    $minutes = (($diff % 3600) - ($diff % 60)) / 60;
    $seconds = $diff % 60;

    // 🔹 Padding
    $hh = ifThenElse(
        $hours < 10,
        string\concatenate('0', $hours),
        $hours
    );

    $mm = ifThenElse(
        $minutes < 10,
        string\concatenate('0', $minutes),
        $minutes
    );

    $ss = ifThenElse(
        $seconds < 10,
        string\concatenate('0', $seconds),
        $seconds
    );

    $formattedTime = string\concatenate(
        string\concatenate($hh, ':'),
        string\concatenate(
            $mm,
            string\concatenate(':', $ss)
        )
    );

    // ✅ Store formatted time
    entity\setAttribute('workDuration', $formattedTime);
    ,
    entity\setAttribute('workDuration', '00:00:00');
);
